mapper.select:
SELECT B.GURU_PORTFOLIOS_ID AS id , B.GURU_ID , A.INVESTOR_NM , A.INVESTOR_KO_NM , A.INVESTOR_NICKNAME , A.INVEST_PHILOSOPHY , A.FAMOUS_QUOTE , B.ISSUER_NM , B.TICKER , B.RANK_NO , B.PORTFOLIO_PCT , C.ACTIVITY_DATE , C.ACTIVITY_YEAR , C.ACTIVITY_QTR , C.CHANGE_PCT , B.REG_DT FROM TBL_GURU A JOIN TBL_GURU_PORTFOLIOS B ON A.GURU_ID = B.GURU_ID LEFT OUTER JOIN ( SELECT * FROM tbl_guru_recent_activity WHERE 1=1
AND ACTIVITY_YEAR = #{searchRequest.activityYear}
AND ACTIVITY_QTR = #{searchRequest.activityQtr}
) C ON A.GURU_CD = C.GURU_CD AND B.TICKER = C.TICKER WHERE 1=1
AND A.INVESTOR_NM LIKE CONCAT('%', #{searchRequest.investorNm}, '%')
AND B.TICKER = #{searchRequest.ticker}
ORDER BY A.GURU_ID, B.RANK_NO
